# Abstract shapes module - provides base class with virtual methods
from models import Color, Dimensions

@abstract
class Shape:
    name: str
    color: Color

    def __init__(self, name: str, color: Color):
        self.name = name
        self.color = color

    @virtual
    def get_info(self) -> str:
        return f"Shape: {self.name}"

    @virtual
    def get_dimensions(self) -> Dimensions:
        return Dimensions(0.0, 0.0)

