# Concrete geometry module - demonstrates cross-module inheritance
from shapes import Shape
from models import Color, Dimensions

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float, color: Color):
        super().__init__(name, color)
        self.radius = radius

    @override
    def get_info(self) -> str:
        return f"Circle: {self.name} (r={self.radius})"

    @override
    def get_dimensions(self) -> Dimensions:
        return Dimensions(self.radius * 2.0, self.radius * 2.0)

    def get_area(self) -> float:
        return 3.14159 * self.radius * self.radius
